window.adminRenderBgDash = function(container){
  container.innerHTML = '';
  container.style.display = 'flex';
  container.style.flexDirection = 'column';
  container.style.overflow = 'hidden';

  // Top bar
  var topbar = document.createElement('div');
  topbar.style.cssText = 'flex-shrink:0;padding:14px 20px 10px;border-bottom:1px solid rgba(255,255,255,.08);display:flex;align-items:center;gap:10px;';
  topbar.innerHTML =
    '<div style="font-family:Montserrat,sans-serif;font-size:13px;font-weight:800;color:var(--tx);">Page Backgrounds</div>'
    + '<div style="font-size:12px;color:var(--dim);margin-left:4px;">Click any page to edit its background</div>';

  // Grid
  var grid = document.createElement('div');
  grid.style.cssText = 'flex:1;overflow-y:auto;padding:20px;';
  grid.innerHTML = _bgRenderGrid();

  container.appendChild(topbar);
  container.appendChild(grid);
};

function _bgRenderGrid(){
  var bgs  = window._PAGE_BACKGROUNDS || {};
  var keys = Object.keys(_BG_PAGE_LABELS);
  return '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px;">'
    + keys.map(function(k){
        var bg  = bgs[k] || {};
        var has = bg.type && bg.type !== 'none' && bg.src;
        var thumb = has
          ? (bg.type === 'video'
              ? '<video autoplay loop muted playsinline src="'+bg.src+'" style="width:100%;height:100%;object-fit:cover;display:block;"></video>'
              : '<img src="'+bg.src+'" style="width:100%;height:100%;object-fit:cover;display:block;">')
          : '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--dim);font-size:11px;font-family:Montserrat,sans-serif;">No BG</div>';
        return '<div onclick="bgOpenEditor(\''+k+'\')" style="border-radius:10px;overflow:hidden;border:1px solid rgba(255,255,255,'+(has?'.18':'.08')+');background:rgba(255,255,255,.03);cursor:pointer;transition:border-color .2s,transform .15s;" onmouseover="this.style.borderColor=\'rgba(236,169,52,.4)\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.borderColor=\'rgba(255,255,255,'+(has?'.18':'.08')+')\';this.style.transform=\'\'">'
          + '<div style="height:90px;overflow:hidden;position:relative;">'
          + thumb
          + (has ? '<div style="position:absolute;top:6px;right:6px;width:8px;height:8px;border-radius:50%;background:#4CAF50;box-shadow:0 0 6px rgba(76,175,80,.8);"></div>' : '')
          + '</div>'
          + '<div style="padding:8px 10px;font-family:Montserrat,sans-serif;font-size:10px;font-weight:800;color:var(--tx);display:flex;align-items:center;justify-content:space-between;">'
          + '<span>'+_BG_PAGE_LABELS[k]+'</span>'
          + '<span style="font-size:9px;color:'+(has?'#4CAF50':'var(--dim)')+'">'+( has ? '● SET' : '○ none' )+'</span>'
          + '</div>'
          + '</div>';
      }).join('')
    + '</div>';
}

window.bgOpenEditor = function(k){
  var container = document.getElementById('adminBgContent');
  if(!container) return;
  container.innerHTML = '';
  container.style.display = 'flex';
  container.style.flexDirection = 'column';
  container.style.overflow = 'hidden';

  var bgs = window._PAGE_BACKGROUNDS || {};
  var bg  = bgs[k] || {};
  var activeType    = bg.type    || 'none';
  var activeOpacity = bg.opacity !== undefined ? bg.opacity : 0.15;
  var activeSrc     = bg.src     || null;

  // Header
  var header = document.createElement('div');
  header.style.cssText = 'flex-shrink:0;padding:14px 20px;border-bottom:1px solid rgba(255,255,255,.08);display:flex;align-items:center;gap:12px;';
  header.innerHTML =
    '<button onclick="window.adminRenderBgDash(document.getElementById(\'adminBgContent\'))" style="background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);color:var(--dim);border-radius:7px;padding:5px 12px;cursor:pointer;font-size:12px;font-family:Montserrat,sans-serif;font-weight:700;">← Back</button>'
    + '<div style="font-family:Montserrat,sans-serif;font-size:14px;font-weight:800;color:var(--tx);">'+_BG_PAGE_LABELS[k]+'</div>'
    + (activeSrc ? '<span style="font-size:9px;padding:3px 9px;border-radius:100px;background:rgba(76,175,80,.12);border:1px solid rgba(76,175,80,.25);color:#4CAF50;font-family:Montserrat,sans-serif;font-weight:700;">● BG SET</span>' : '');

  // Body — editor left, preview right
  var body = document.createElement('div');
  body.style.cssText = 'flex:1;display:flex;flex-direction:row;overflow:hidden;';

  // Editor panel
  var edPanel = document.createElement('div');
  edPanel.style.cssText = 'flex:1;overflow-y:auto;padding:24px;max-width:480px;';
  edPanel.id = 'bgEditorPanel_'+k;

  function buildEditorHTML(type, src, opacity){
    var op = opacity !== undefined ? opacity : 0.15;
    return '<div class="admin-field"><label style="font-family:Montserrat,sans-serif;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--dim);">Background Type</label>'
      + '<div style="display:flex;gap:6px;margin-top:6px;">'
      + ['image','video','none'].map(function(t){
          var labels = {image:'🖼 Image / GIF', video:'🎬 Video', none:'✕ None'};
          return '<button onclick="bgSetTypeEditor(\''+k+'\',\''+t+'\')" style="flex:1;padding:8px;border-radius:8px;border:1px solid rgba(255,255,255,'+(type===t?'.3':'.1')+');background:rgba(255,255,255,'+(type===t?'.1':'.03')+');color:'+(type===t?'var(--tx)':'var(--dim)')+';font-family:Montserrat,sans-serif;font-size:11px;font-weight:700;cursor:pointer;">'+labels[t]+'</button>';
        }).join('')
      + '</div></div>'
      + (type !== 'none' ?
        '<div class="admin-field">'
        + '<label style="font-family:Montserrat,sans-serif;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--dim);">Upload '+(type==='video'?'Video (MP4, WebM)':'Image or GIF')+'</label>'
        + '<div onclick="document.getElementById(\'bgFileInput_'+k+'\').click()" style="margin-top:6px;border:2px dashed rgba(255,255,255,.12);border-radius:10px;padding:24px;text-align:center;cursor:pointer;transition:all .2s;" onmouseover="this.style.borderColor=\'rgba(236,169,52,.4)\'" onmouseout="this.style.borderColor=\'rgba(255,255,255,.12)\'">'
        + '<input type="file" id="bgFileInput_'+k+'" style="display:none;" accept="'+(type==='video'?'video/*':'image/*,.gif')+'" onchange="bgHandleFileEditor(\''+k+'\',this)">'
        + '<div style="font-size:24px;margin-bottom:6px;">'+(src?'✓':'📁')+'</div>'
        + '<div style="font-size:12px;color:var(--dim);">'+(src?'File uploaded — click to replace':'Click to upload')+'</div>'
        + '</div></div>'
        : '')
      + (src ?
        '<div class="admin-field"><label style="font-family:Montserrat,sans-serif;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.09em;color:var(--dim);">Page Overlay Opacity <span style="color:var(--tx);" id="bgOpVal_'+k+'">'+Math.round(op*100)+'%</span></label>'
        + '<input type="range" min="0" max="0.95" step="0.01" value="'+op+'" oninput="bgUpdateOpacityEditor(\''+k+'\',this.value)" style="width:100%;margin-top:8px;accent-color:var(--t);">'
        + '<div style="font-size:11px;color:var(--dim);margin-top:4px;">Lower = background more visible. Applies dark overlay on top of background.</div>'
        + '</div>'
        : '')
      + (src ?
        '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px;">'
        + '<button class="admin-save" onclick="bgApplyEditor(\''+k+'\')">✓ Apply to Page</button>'
        + '<button onclick="bgPreviewEditor(\''+k+'\')" style="background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);color:var(--mid);border-radius:8px;padding:10px 18px;font-family:Montserrat,sans-serif;font-weight:700;font-size:12px;cursor:pointer;">👁 Preview on Site</button>'
        + '<button class="admin-del-btn" onclick="bgClearEditor(\''+k+'\')">Remove BG</button>'
        + '</div>'
        : (type !== 'none' ? '<p style="font-size:12px;color:var(--dim);margin-top:8px;">Upload a file to apply it.</p>' : '<p style="font-size:12px;color:var(--dim);margin-top:8px;">No background will be shown for this page.</p>'))
      ;
  }

  edPanel.innerHTML = buildEditorHTML(activeType, activeSrc, activeOpacity);
  edPanel._buildEditorHTML = buildEditorHTML;

  // Preview panel
  var pvPanel = document.createElement('div');
  pvPanel.style.cssText = 'flex:1;display:flex;flex-direction:column;border-left:1px solid rgba(255,255,255,.08);overflow:hidden;min-width:240px;';
  pvPanel.innerHTML =
    '<div style="flex-shrink:0;padding:12px 16px;font-family:Montserrat,sans-serif;font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.08em;color:var(--dim);border-bottom:1px solid rgba(255,255,255,.08);">Preview</div>'
    + '<div id="bgPreviewPanel_'+k+'" style="flex:1;overflow:hidden;position:relative;background:#080B1A;">'
    + _bgBuildPreview(activeSrc, activeType, activeOpacity)
    + '</div>';

  body.appendChild(edPanel);
  body.appendChild(pvPanel);
  container.appendChild(header);
  container.appendChild(body);

  // Store state
  window._bgEditorState = window._bgEditorState || {};
  window._bgEditorState[k] = { type: activeType, src: activeSrc, opacity: activeOpacity };
};

function _bgBuildPreview(src, type, opacity){
  if(!src || type === 'none') return '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--dim);font-size:12px;">No background set</div>';
  var media = type === 'video'
    ? '<video autoplay loop muted playsinline src="'+src+'" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;"></video>'
    : '<img src="'+src+'" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;">';
  return media + '<div style="position:absolute;inset:0;background:rgba(8,11,26,'+((opacity||0.15).toFixed(2))+');"></div>'
    + '<div style="position:absolute;bottom:12px;left:50%;transform:translateX(-50%);font-size:10px;color:rgba(255,255,255,.5);font-family:Montserrat,sans-serif;white-space:nowrap;">Overlay: '+Math.round((opacity||0.15)*100)+'%</div>';
}

window.bgSetTypeEditor = function(k, type){
  if(!window._bgEditorState) window._bgEditorState = {};
  if(!window._bgEditorState[k]) window._bgEditorState[k] = {};
  window._bgEditorState[k].type = type;
  if(type === 'none'){
    window._bgEditorState[k].src = null;
  }
  var panel = document.getElementById('bgEditorPanel_'+k);
  if(panel){
    var st = window._bgEditorState[k];
    panel.innerHTML = panel._buildEditorHTML(st.type, st.src, st.opacity);
    panel._buildEditorHTML = panel._buildEditorHTML; // preserve reference
  }
};

window.bgHandleFileEditor = function(k, input){
  var file = input.files[0];
  if(!file) return;
  if(file.size > 20*1024*1024){ alert('File too large — max 20MB'); return; }
  var reader = new FileReader();
  reader.onload = function(e){
    var type = file.type.startsWith('video') ? 'video' : 'image';
    if(!window._bgEditorState) window._bgEditorState = {};
    if(!window._bgEditorState[k]) window._bgEditorState[k] = {};
    window._bgEditorState[k].src  = e.target.result;
    window._bgEditorState[k].type = type;
    // Rebuild editor
    var panel = document.getElementById('bgEditorPanel_'+k);
    if(panel && panel._buildEditorHTML){
      var st = window._bgEditorState[k];
      panel.innerHTML = panel._buildEditorHTML(st.type, st.src, st.opacity||0.15);
    }
    // Update preview
    var pvPanel = document.getElementById('bgPreviewPanel_'+k);
    if(pvPanel){
      var st = window._bgEditorState[k];
      pvPanel.innerHTML = _bgBuildPreview(st.src, st.type, st.opacity||0.15);
    }
  };
  reader.readAsDataURL(file);
};

window.bgUpdateOpacityEditor = function(k, val){
  var opacity = parseFloat(val);
  if(!window._bgEditorState) window._bgEditorState = {};
  if(!window._bgEditorState[k]) window._bgEditorState[k] = {};
  window._bgEditorState[k].opacity = opacity;
  var valEl = document.getElementById('bgOpVal_'+k);
  if(valEl) valEl.textContent = Math.round(opacity*100)+'%';
  var pvPanel = document.getElementById('bgPreviewPanel_'+k);
  if(pvPanel){
    var st = window._bgEditorState[k];
    pvPanel.innerHTML = _bgBuildPreview(st.src, st.type, opacity);
  }
};

window.bgApplyEditor = function(k){
  var st = window._bgEditorState && window._bgEditorState[k];
  if(!st || !st.src) return;
  if(!window._PAGE_BACKGROUNDS) window._PAGE_BACKGROUNDS = {};
  window._PAGE_BACKGROUNDS[k] = { type: st.type, src: st.src, opacity: st.opacity||0.15 };
  _applyPageBackground(window._currentPage || 'home');
  _adminToast('Background applied to '+_BG_PAGE_LABELS[k]+' \u2713');
};

window.bgPreviewEditor = function(k){
  // Close admin and navigate to that page
  closeAdmin();
  go(k);
};

window.bgClearEditor = function(k){
  if(!confirm('Remove background from '+_BG_PAGE_LABELS[k]+'?')) return;
  if(window._PAGE_BACKGROUNDS) window._PAGE_BACKGROUNDS[k] = { type:'none', src:null, opacity:0.15 };
  if(window._bgEditorState && window._bgEditorState[k]){
    window._bgEditorState[k] = { type:'none', src:null, opacity:0.15 };
  }
  _applyPageBackground(window._currentPage || 'home');
  _adminToast('Background removed \u2713');
  // Rebuild editor
  var container = document.getElementById('adminBgContent');
  if(container) window.adminRenderBgDash(container);
};

