// ── PAGE BACKGROUND RENDERER ─────────────────────────────────────────────────
function _applyPageBackground(page){
  var bgEl = document.getElementById('pageBgLayer');
  if(!bgEl) return;
  var bgs = window._PAGE_BACKGROUNDS || {};
  // Match zoho sub-pages to their key
  var key = page;
  if(!bgs[key]) key = 'home';
  var bg = bgs[key];
  if(!bg || bg.type === 'none' || !bg.src){
    bgEl.style.display = 'none';
    bgEl.innerHTML = '';
    return;
  }
  bgEl.style.display = 'block';
  bgEl.style.opacity = bg.opacity || 0.15;
  if(bg.type === 'image' || bg.type === 'gif'){
    bgEl.innerHTML = '<img src="'+bg.src+'" style="width:100%;height:100%;object-fit:cover;display:block">';
  } else if(bg.type === 'video'){
    bgEl.innerHTML = '<video autoplay loop muted playsinline style="width:100%;height:100%;object-fit:cover;display:block" src="'+bg.src+'"></video>';
  }
}



// ── NAV RENDERER ─────────────────────────────────────────────────────────────
function _renderNav(){
  var nl = document.getElementById('navLinks');
  if(!nl) return;
  var pages = window._NAV_PAGES || [];
  nl.innerHTML = pages.filter(function(p){ return p.enabled; }).map(function(p){
    return '<a href="#" onclick="go(\'' + p.key + '\')">' + p.label + '</a>';
  }).join('');
  // Re-apply active state
  var app = document.getElementById('app');
  if(app && window._currentPage){
    _highlightNav(window._currentPage);
  }
}

function _highlightNav(page){
  document.querySelectorAll('#navLinks a').forEach(function(a){
    var onclick = a.getAttribute('onclick') || '';
    var m = onclick.match(/go\(['"]([^'"]+)['"]\)/);
    var linkPage = m ? m[1] : '';
    a.classList.toggle('on', linkPage === page);
  });
}


// ── SUBMISSIONS ───────────────────────────────────────────────────────────────
window._SUBMISSIONS = [];

window.submitForm = function(e){
  e.preventDefault();
  var fname    = document.getElementById('fname')    ? document.getElementById('fname').value.trim()    : '';
  var lname    = document.getElementById('lname')    ? document.getElementById('lname').value.trim()    : '';
  var email    = document.getElementById('email')    ? document.getElementById('email').value.trim()    : '';
  var company  = document.getElementById('company')  ? document.getElementById('company').value.trim()  : '';
  var size     = document.getElementById('size')     ? document.getElementById('size').value.trim()     : '';
  var message  = document.getElementById('message')  ? document.getElementById('message').value.trim()  : '';
  var timeline = document.getElementById('timeline') ? document.getElementById('timeline').value.trim() : '';
  // Collect selected service chips
  var chips    = document.querySelectorAll('#svcChips .svc-chip.active');
  var services = Array.from(chips).map(function(c){ return c.textContent.trim(); });

  var submission = {
    id:        Date.now(),
    datetime:  new Date().toLocaleString(),
    name:      (fname + ' ' + lname).trim(),
    email:     email,
    company:   company,
    size:      size,
    timeline:  timeline,
    services:  services,
    message:   message,
    status:    'New',
    contacted: false,
  };
  window._SUBMISSIONS.unshift(submission);

  var btn = document.getElementById('submitBtn');
  if(btn){ btn.textContent='Sending...'; btn.style.opacity='.7'; btn.disabled=true; }
  setTimeout(function(){
    var fw = document.getElementById('formWrap');
    var ss = document.getElementById('successState');
    if(fw) fw.style.display = 'none';
    if(ss) ss.style.display = 'block';
  }, 1200);
};

window.updateChar = function(el){
  var l = el.value.length;
  var cc = document.getElementById('charCount');
  if(cc) cc.textContent = l + ' / 1000';
  if(l > 1000) el.value = el.value.slice(0, 1000);
};

